let player = {
    x: 0,
    y: 0,
    speed: 100, // pixels per second
    lastMoveTime: Date.now()
};

let keysDown = {
    ArrowUp: false,
    ArrowDown: false,
    ArrowLeft: false,
    ArrowRight: false
};

window.addEventListener('keydown', function(event) {
    keysDown[event.key] = true;
});

window.addEventListener('keyup', function(event) {
    keysDown[event.key] = false;
});

function gameLoop() {
    let now = Date.now();
    let dt = (now - player.lastMoveTime) / 1000; // in seconds
    player.lastMoveTime = now;

    if (keysDown['ArrowUp']) player.y -= player.speed * dt;
    if (keysDown['ArrowDown']) player.y += player.speed * dt;
    if (keysDown['ArrowLeft']) player.x -= player.speed * dt;
    if (keysDown['ArrowRight']) player.x += player.speed * dt;

    // Redraw game
    context.clearRect(0, 0, canvas.width, canvas.height);
    context.fillRect(player.x, player.y, 50, 50);
}

let canvas = document.createElement('canvas');
let context = canvas.getContext('2d');
document.body.appendChild(canvas);
canvas.width = window.innerWidth;
canvas.height = window.innerHeight;

setInterval(gameLoop, 1000 / 60); // 60 FPS